    int noOfDrivers(vector<vector<int>>& rides) {
	  sort(rides.begin(), rides.end());
	  multiset <pair<int,int>> drivers;
	  int requiredDrivers = 0;
	  for(auto& ride : rides){

		bool needNewDriver = true;
		while(!drivers.empty())
		{
			auto it = drivers.begin();
			int rideEndTime = (*it).first;
			int rideCount = (*it).second;
			if(rideCount==3){
				drivers.erase(it);
			}
			else if(rideEndTime>=ride[0]) {
				break;
			}
			else {
				needNewDriver=false; break;
			}
		}

		if(needNewDriver)  { requiredDrivers++;   drivers.insert({ride[1],1}); }
		else  {
			auto it = drivers.begin();
			int count = (*it).second;
			drivers.erase(it);  
			drivers.insert({ride[1], count+1});
		} 
	  }
	  return requiredDrivers;
    }
